  public_evidence_json = '["Tracked by issue #18.", "Issue #87 adds the first /analytics/source-data contract and /analytics/indie-launch-dashboard preview scaffold.", "Issue #105 adds POST /api/analytics/events with seeded event validation, idempotency, hashed request evidence, and aggregate-only source-data reporting.", "Issue #107 adds POST /api/analytics/assignments with seeded experiment validation, deterministic weighted variant assignment, hashed visitor evidence, and aggregate-only assignment reporting.", "Issue #119 adds aggregate funnel conversion report rows from captured test events without exposing raw analytics rows.", "Issue #121 adds browser-side funnel page-view beacons with server-side bot and preview suppression.", "Issue #123 attaches deterministic seeded assignment evidence to captured funnel page views and exposes aggregate variant counts.", "Issue #125 attaches normalized UTM/source attribution to captured funnel page views and exposes aggregate source counts.", "Issue #127 renders aggregate source attribution rows in the analytics dashboard preview."]',
